// Utilities
import { toRef } from 'vue'
import { getCurrentInstanceName, propsFactory } from '@/util'

// Types
import type { PropType } from 'vue'

const positionValues = ['static', 'relative', 'fixed', 'absolute', 'sticky'] as const

type Position = typeof positionValues[number]

export interface PositionProps {
  position: Position | undefined
}

// Composables
export const makePositionProps = propsFactory({
  position: {
    type: String as PropType<Position>,
    validator: /* istanbul ignore next */ (v: any) => positionValues.includes(v),
  },
}, 'position')

export function usePosition (
  props: PositionProps,
  name = getCurrentInstanceName(),
) {
  const positionClasses = toRef(() => {
    return props.position ? `${name}--${props.position}` : undefined
  })

  return { positionClasses }
}

import {type Plugin, ref, type Ref} from 'vue'
import type {
  BootstrapVueOptions,
  BvnComponentProps,
  BvnComponents,
} from '../../types/BootstrapVueOptions'

import '../../styles/styles.scss'

import {rtlPlugin} from '../rtl'
import {registryPlugin} from '../registry'
import {orchestratorPlugin} from '../orchestrator'
import {defaultsKey} from '../../utils/keys'

// Main app plugin
export const createBootstrap = (pluginData: Readonly<BootstrapVueOptions> = {}): Plugin => ({
  install(app) {
    if ((pluginData.registries ?? true) === true) {
      app.use(registryPlugin, pluginData)
    }
    if ((pluginData.rtl ?? true) === true || typeof pluginData.rtl === 'object') {
      app.use(rtlPlugin, pluginData)
    }
    if ((pluginData.orchestrator ?? true) === true) {
      app.use(orchestratorPlugin)
    }
    // Provide global defaults for components
    const val = pluginData?.components ?? {}
    app.provide(defaultsKey, ref(val) as Ref<Partial<BvnComponentProps>>)
  },
})

declare module 'vue' {
  // eslint-disable-next-line @typescript-eslint/no-empty-object-type
  interface GlobalComponents extends BvnComponents {}
}

import { createBootstrap as createBootstrapVue } from 'bootstrap-vue-next/plugins/createBootstrap'
import { defineNuxtPlugin, useRuntimeConfig } from '#app'

export default defineNuxtPlugin((nuxtApp) => {
  const opts = useRuntimeConfig().public.bootstrapVueNext.plugin

  nuxtApp.vueApp.use(
    createBootstrapVue({
      ...opts,
      components: {
        ...opts?.components,
        BModal: {
          teleportTo: '#teleports',
          ...opts?.components?.BModal,
        },
        BOffcanvas: {
          teleportTo: '#teleports',
          ...opts?.components?.BOffcanvas,
        },
        BOrchestrator: {
          teleportTo: '#teleports',
          ...opts?.components?.BOrchestrator,
        },
        BApp: {
          teleportTo: '#teleports',
          ...opts?.components?.BApp,
        },
        BLink: {
          routerComponentName: 'RouterLink',
          ...opts?.components?.BLink,
        },
      },
    }),
  )
})

import type { App, Component, InjectionKey } from 'vue'

// use `name` to register a Functional Component which will become unresolvable
// in production build due to name mangling.
export const registerComponent = (Vue: App, component: Component, name?: string) => {
    const componentName = name || component.name
    if (componentName == null) {
        throw new Error('Buefy.registerComponent: missing component name')
    }
    Vue.component(componentName, component)
}

export const registerComponentProgrammatic = <
    K extends keyof App['config']['globalProperties']['$buefy'],
    C extends App['config']['globalProperties']['$buefy'][K]
>(Vue: App, property: K, component: C, injectionKey: InjectionKey<C>) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    if (!Vue.config.globalProperties.$buefy) Vue.config.globalProperties.$buefy = {} as any
    Vue.config.globalProperties.$buefy[property] = component
    Vue.provide(injectionKey, component)
}

import { defineComponent, h as createElement } from 'vue'

export default defineComponent({
    name: 'BSlotComponent',
    props: {
        component: {
            type: Object,
            required: true
        },
        name: {
            type: String,
            default: 'default'
        },
        scoped: {
            type: Boolean
        },
        props: {
            type: Object
        },
        tag: {
            type: [String, Object],
            default: 'div'
        }
    },
    methods: {
        refresh() {
            this.$forceUpdate()
        }
    },
    render() {
        return createElement(this.tag, {},
            this.component.$slots
                ? this.scoped
                    ? this.component.$slots[this.name](this.props)
                    : this.component.$slots[this.name]()
                : undefined)
    }
})

import { ref } from 'vue'

type Theme = 'light' | 'dark'

function getTheme(): Theme {
    const stored = localStorage.getItem('theme') as Theme | null
    if (stored === 'light' || stored === 'dark') return stored
    if (window.matchMedia('(prefers-color-scheme: dark)').matches) return 'dark'
    return 'light'
}

const isLight = ref(getTheme() === 'light')

function setTheme(theme: Theme): void {
    isLight.value = theme === 'light'
    localStorage.setItem('theme', theme)
    document.documentElement.classList.toggle('theme-dark', theme === 'dark')
    document.documentElement.classList.toggle('theme-light', theme === 'light')
}

function toggleTheme(): void {
    setTheme(isLight.value ? 'dark' : 'light')
}

export function useTheme() {
    return { isLight, getTheme, setTheme, toggleTheme }
}

import { isDate, isObject, isUndefinedOrNull } from './inspect'
import { keys } from './object'
import { toString } from './string'

// Recursively stringifies the values of an object, space separated, in an
// SSR safe deterministic way (keys are sorted before stringification)
//
//   ex:
//     { b: 3, c: { z: 'zzz', d: null, e: 2 }, d: [10, 12, 11], a: 'one' }
//   becomes
//     'one 3 2 zzz 10 12 11'
//
// Strings are returned as-is
// Numbers get converted to string
// `null` and `undefined` values are filtered out
// Dates are converted to their native string format
export const stringifyObjectValues = value => {
  if (isUndefinedOrNull(value)) {
    return ''
  }
  // Arrays are also object, and keys just returns the array indexes
  // Date objects we convert to strings
  if (isObject(value) && !isDate(value)) {
    return keys(value)
      .sort() // Sort to prevent SSR issues on pre-rendered sorted tables
      .map(k => stringifyObjectValues(value[k]))
      .filter(v => !!v) // Ignore empty strings
      .join(' ')
  }
  return toString(value)
}

export const useDelayedToggle = ({
  showAfter,
  hideAfter,
  autoClose,
  open,
  close,
}: DelayedToggle) => {
  const { registerTimeout } = useTimeout()
  const {
    registerTimeout: registerTimeoutForAutoClose,
    cancelTimeout: cancelTimeoutForAutoClose,
  } = useTimeout()

  const onOpen = (event?: Event, delay = unref(showAfter)) => {
    registerTimeout(() => {
      open(event)

      const _autoClose = unref(autoClose)
      if (isNumber(_autoClose) && _autoClose > 0) {
        registerTimeoutForAutoClose(() => {
          close(event)
        }, _autoClose)
      }
    }, delay)
  }

  const onClose = (event?: Event, delay = unref(hideAfter)) => {
    cancelTimeoutForAutoClose()
    registerTimeout(() => {
      close(event)
    }, delay)
  }

  return {
    onOpen,
    onClose,
  }
}

// Utilities
import { convertToUnit, destructComputed, getCurrentInstanceName, includes, propsFactory } from '@/util'

// Types
const predefinedSizes = ['x-small', 'small', 'default', 'large', 'x-large']

export interface SizeProps {
  size?: string | number
}

// Composables
export const makeSizeProps = propsFactory({
  size: {
    type: [String, Number],
    default: 'default',
  },
}, 'size')

export function useSize (
  props: SizeProps,
  name = getCurrentInstanceName(),
) {
  return destructComputed(() => {
    const size = props.size
    let sizeClasses
    let sizeStyles
    if (includes(predefinedSizes, size)) {
      sizeClasses = `${name}--size-${size}`
    } else if (size) {
      sizeStyles = {
        width: convertToUnit(size),
        height: convertToUnit(size),
      }
    }
    return { sizeClasses, sizeStyles }
  })
}

// Types
import type { DirectiveBinding } from 'vue'

interface ResizeDirectiveBinding extends Omit<DirectiveBinding, 'modifiers'> {
  value: () => void
  modifiers?: {
    active?: boolean
    quiet?: boolean
  }
}

function mounted (el: HTMLElement, binding: ResizeDirectiveBinding) {
  const handler = binding.value
  const options: AddEventListenerOptions = {
    passive: !binding.modifiers?.active,
  }

  window.addEventListener('resize', handler, options)

  el._onResize = Object(el._onResize)
  el._onResize![binding.instance!.$.uid] = {
    handler,
    options,
  }

  if (!binding.modifiers?.quiet) {
    handler()
  }
}

function unmounted (el: HTMLElement, binding: ResizeDirectiveBinding) {
  if (!el._onResize?.[binding.instance!.$.uid]) return

  const { handler, options } = el._onResize[binding.instance!.$.uid]!

  window.removeEventListener('resize', handler, options)

  delete el._onResize[binding.instance!.$.uid]
}

export const Resize = {
  mounted,
  unmounted,
}

export default Resize

import { defineComponent } from 'vue'
import type { StyleValue } from 'vue'

import config from './config'

export default defineComponent({
    inheritAttrs: false,
    props: {
        compatFallthrough: {
            type: Boolean,
            default: () => config.defaultCompatFallthrough
        }
    },
    computed: {
        rootAttrs() {
            return this.compatFallthrough
                ? {
                    class: this.$attrs.class,
                    style: this.$attrs.style as StyleValue,
                    id: this.$attrs.id as string | undefined
                }
                : {}
        },
        fallthroughAttrs() {
            if (this.compatFallthrough) {
                // eslint-disable-next-line @typescript-eslint/no-unused-vars
                const { style: _1, class: _2, id: _3, ...rest } = this.$attrs
                return rest
            } else {
                return this.$attrs
            }
        }
    }
})

import { BForm } from './form'
import { BFormDatalist } from './form-datalist'
import { BFormText } from './form-text'
import { BFormInvalidFeedback } from './form-invalid-feedback'
import { BFormValidFeedback } from './form-valid-feedback'
import { BFormRow } from '../layout/form-row'
import { pluginFactory } from '../../utils/plugins'

const FormPlugin = /*#__PURE__*/ pluginFactory({
  components: {
    BForm,
    BFormDatalist,
    BDatalist: BFormDatalist,
    BFormText,
    BFormInvalidFeedback,
    BFormFeedback: BFormInvalidFeedback,
    BFormValidFeedback,
    // Added here for convenience
    BFormRow
  }
})

// BFormRow is not exported here as a named export, as it is exported by Layout
export { FormPlugin, BForm, BFormDatalist, BFormText, BFormInvalidFeedback, BFormValidFeedback }

export default async function (_, _nuxt) {
  const { addPluginTemplate } = await import('@nuxt/kit')

  const nuxt = (this && this.nuxt) || _nuxt

  nuxt.options.css.push('floating-vue/dist/style.css')

  addPluginTemplate({
    filename: 'floating-vue.mjs',
    getContents: () => `
      import { defineNuxtPlugin } from '#imports'
      import FloatingVue from 'floating-vue'

      export default defineNuxtPlugin((nuxtApp) => {
        // @TODO cutomization
        nuxtApp.vueApp.use(FloatingVue)
      })
    `,
  })

  // @TODO remove when floating-ui supports native ESM
  nuxt.options.build.transpile.push('floating-vue', '@floating-ui/core', '@floating-ui/dom')

  // SSR support for v-tooltip directive
  nuxt.options.vue.compilerOptions.directiveTransforms = nuxt.options.vue.compilerOptions.directiveTransforms || {}
  nuxt.options.vue.compilerOptions.directiveTransforms.tooltip = () => ({
    props: [],
    needRuntime: true,
  })
}
